const isLocked = () => new Date() >= DEADLINE;
const timeLeft = () => {
  const d = DEADLINE - new Date();
  if (d <= 0) return null;
  const days = Math.floor(d/(1000*60*60*24));
  const hrs = Math.floor((d%(1000*60*60*24))/(1000*60*60));
  const mins = Math.floor((d%(1000*60*60))/(1000*60));
  if (days > 0) return `${days}d ${hrs}h`;
  if (hrs > 0) return `${hrs}h ${mins}min`;
  return `${mins} minutes`;
};

const GROUP_MATCHES = Object.entries(GROUPS).flatMap(([g,teams]) => {
  const m=[];
  for(let i=0;i<teams.length;i++)
    for(let j=i+1;j<teams.length;j++)
      m.push({id:`${g}${i}${j}`,group:g,home:teams[i],away:teams[j]});
  return m;
});

// ─── STANDINGS & BRACKET LOGIC ────────────────────────────────────────────────
function computeStandings(gid, scores) {
  const teams=GROUPS[gid], s={};
  teams.forEach(t=>{s[t]={pts:0,gf:0,ga:0,gd:0,pl:0};});
  GROUP_MATCHES.filter(m=>m.group===gid).forEach(m=>{
    const sc=scores?.[m.id];
    if(!sc||sc.h==null||sc.a==null) return;
    const h=+sc.h,a=+sc.a;
    if(isNaN(h)||isNaN(a)) return;
    s[m.home].pl++;s[m.away].pl++;
    s[m.home].gf+=h;s[m.home].ga+=a;s[m.home].gd+=h-a;
    s[m.away].gf+=a;s[m.away].ga+=h;s[m.away].gd+=a-h;
    if(h>a)s[m.home].pts+=3;else if(h<a)s[m.away].pts+=3;
    else{s[m.home].pts++;s[m.away].pts++;}
  });
  return teams.map(t=>({...s[t],team:t,group:gid})).sort((a,b)=>b.pts-a.pts||b.gd-a.gd||b.gf-a.gf);
}

function allGroupsFilled(scores) {
  return GROUP_MATCHES.every(m=>{const s=scores?.[m.id];return s&&s.h!=null&&s.a!=null;});
}
function getGroupPct(scores) {
  const filled=GROUP_MATCHES.filter(m=>{const s=scores?.[m.id];return s&&s.h!=null&&s.a!=null;}).length;
  return Math.round((filled/GROUP_MATCHES.length)*100);
}

// Get 8 best 3rd place teams, sorted by pts > gd > gf
function getBest8Thirds(scores) {
  const thirds = Object.keys(GROUPS).map(g=>{
    const st=computeStandings(g,scores);
    return st[2]?{...st[2],group:g}:null;
  }).filter(Boolean);
  thirds.sort((a,b)=>b.pts-a.pts||b.gd-a.gd||b.gf-a.gf);
  return thirds.slice(0,8);
}

// Official FIFA 2026 R32: which cluster of 3rd-place groups each group winner draws from
// Source: ESPN official schedule & Wikipedia group articles
const THIRD_CLUSTERS = {
  A: ['C','E','F','H','I'],
  E: ['A','B','C','D','F'],
  I: ['C','D','F','G','H'],
  L: ['E','H','I','J','K'],
  G: ['A','E','H','I','J'],
  D: ['B','E','F','I','J'],
  K: ['D','E','I','J','L'],
  B: ['A','C','D','F','G','J','K','L'],
};

// Official FIFA 2026 R32 structure (from official regulations + USA Today bracket)
// thirds: array of {group, team} — the 8 manually selected best 3rd place teams
function buildR32(scores, thirds) {
  const q = {};
  Object.keys(GROUPS).forEach(g => {
    const st = computeStandings(g, scores);
    q[`${g}1`] = st[0]?.team || `1st ${g}`;
    q[`${g}2`] = st[1]?.team || `2nd ${g}`;
  });

  // Official FIFA 2026 cluster assignments per group winner
  // Source: USA Today official bracket / FIFA regulations
  const CLUSTERS = {
    A: ['C','E','F','H','I'],
    E: ['A','B','C','D','F'],
    I: ['C','D','F','G','H'],
    L: ['E','H','I','J','K'],
    D: ['B','E','F','I','J'],
    G: ['A','E','H','I','J'],
    K: ['D','E','I','J','L'],
    B: ['A','C','D','F','G','J','K','L'], // gets last remaining 3rd
  };

  // Assign 3rds to slots — use manual selection, respect no-rematch rule
  const assigned = {};
  const used = new Set();
  const slotOrder = ['A','E','I','L','D','G','K','B'];

  if (thirds && thirds.length > 0) {
    slotOrder.forEach(slot => {
      const cluster = CLUSTERS[slot] || [];
      // Find best 3rd (by order in thirds array) from cluster not yet used and not from own group
      const pick = thirds.find(t => cluster.includes(t.group) && !used.has(t.group) && t.group !== slot);
      if (pick) { assigned[slot] = pick.team; used.add(pick.group); }
      else {
        // fallback: any unused 3rd not from own group
        const fallback = thirds.find(t => !used.has(t.group) && t.group !== slot);
        if (fallback) { assigned[slot] = fallback.team; used.add(fallback.group); }
        else assigned[slot] = '?';
      }
    });
  } else {
    slotOrder.forEach(slot => { assigned[slot] = '3rd TBD'; });
  }

  return [
    // ── FIXED matchups (official FIFA 2026) ──
    {id:'r32-1',  home:q.A2, away:q.B2,  label:'A2 vs B2'},
    {id:'r32-2',  home:q.C1, away:q.F2,  label:'C1 vs F2'},
    {id:'r32-3',  home:q.F1, away:q.C2,  label:'F1 vs C2'},
    {id:'r32-4',  home:q.E2, away:q.I2,  label:'E2 vs I2'},
    {id:'r32-5',  home:q.H1, away:q.J2,  label:'H1 vs J2'},
    {id:'r32-6',  home:q.J1, away:q.H2,  label:'J1 vs H2'},
    {id:'r32-7',  home:q.K2, away:q.L2,  label:'K2 vs L2'},
    {id:'r32-8',  home:q.D2, away:q.G2,  label:'D2 vs G2'},
    // ── VARIABLE matchups (group winner vs best 3rd) ──
    {id:'r32-9',  home:q.E1, away:assigned.E, label:`E1 vs 3rd(A/B/C/D/F)`},
    {id:'r32-10', home:q.I1, away:assigned.I, label:`I1 vs 3rd(C/D/F/G/H)`},
    {id:'r32-11', home:q.A1, away:assigned.A, label:`A1 vs 3rd(C/E/F/H/I)`},
    {id:'r32-12', home:q.L1, away:assigned.L, label:`L1 vs 3rd(E/H/I/J/K)`},
    {id:'r32-13', home:q.D1, away:assigned.D, label:`D1 vs 3rd(B/E/F/I/J)`},
    {id:'r32-14', home:q.G1, away:assigned.G, label:`G1 vs 3rd(A/E/H/I/J)`},
    {id:'r32-15', home:q.K1, away:assigned.K, label:`K1 vs 3rd(D/E/I/J/L)`},
    {id:'r32-16', home:q.B1, away:assigned.B, label:`B1 vs 3rd`},
  ];
}

// ─── AUTH & SCORING ───────────────────────────────────────────────────────────
function hashPw(s){let h=0;for(let i=0;i<s.length;i++)h=(Math.imul(31,h)+s.charCodeAt(i))|0;return h.toString(36);}

function calcPoints(pr,res) {
  if(!pr||!res) return 0;
  let pts=0;
  GROUP_MATCHES.forEach(m=>{
    const p=pr.groupScores?.[m.id],r=res.groupScores?.[m.id];
    if(!p||!r||p.h==null||r.h==null) return;
    if(+p.h===+r.h&&+p.a===+r.a) pts+=POINTS.exactScore;
    else if(Math.sign(+p.h-+p.a)===Math.sign(+r.h-+r.a)) pts+=POINTS.correctResult;
  });
  ["r32","r16","qf","sf","final"].forEach(round=>{
    const rp=res.knockout?.[round]||{},pp=pr.knockout?.[round]||{};
    Object.keys(rp).forEach(k=>{if(pp[k]&&pp[k]===rp[k])pts+=POINTS.knockoutWinner;});
  });
  const pC=pr.champion==="__other__"?pr.championOther:pr.champion;
  const pS=pr.topScorer==="__other__"?pr.topScorerOther:pr.topScorer;
  if(pC&&res.champion&&pC.trim().toLowerCase()===res.champion.trim().toLowerCase()) pts+=POINTS.champion;
  if(pS&&res.topScorer&&pS.trim().toLowerCase()===res.topScorer.trim().toLowerCase()) pts+=POINTS.topScorer;
  if(pr.darkHorse&&res.darkHorse&&pr.darkHorse.trim().toLowerCase()===res.darkHorse.trim().toLowerCase()) pts+=POINTS.darkHorse;
  return pts;
}

