// ─── AUTH ─────────────────────────────────────────────────────────────────────
function AuthView({onLogin}){
  const [mode,setMode]=useState("login");
  const [f,setF]=useState({prenom:"",nom:"",email:"",pw:"",pw2:""});
  const [err,setErr]=useState("");
  const [loading,setLoading]=useState(false);

  const submit=async()=>{
    setErr("");setLoading(true);
    const key=f.email.toLowerCase().trim();
    if(mode==="register"){
      if(!f.prenom||!f.nom||!f.email||!f.pw){setErr("All fields are required.");setLoading(false);return;}
      if(f.pw!==f.pw2){setErr("Passwords do not match.");setLoading(false);return;}
      if(f.pw.length<6){setErr("Password too short (min. 6 characters).");setLoading(false);return;}
      if(await fbGetUser(key)){setErr("Email already in use.");setLoading(false);return;}
      await fbSetUser({id:key,prenom:f.prenom.trim(),nom:f.nom.trim(),email:key,pw:hashPw(f.pw),isAdmin:false,createdAt:Date.now()});
      onLogin({id:key,prenom:f.prenom.trim(),nom:f.nom.trim(),email:key,isAdmin:false});
    } else {
      if(key===ADMIN_EMAIL&&f.pw===ADMIN_PWD){onLogin({id:ADMIN_EMAIL,prenom:"Admin",nom:"AESMSL",email:ADMIN_EMAIL,isAdmin:true});setLoading(false);return;}
      const user=await fbGetUser(key);
      if(!user||user.pw!==hashPw(f.pw)){setErr("Incorrect email or password.");setLoading(false);return;}
      onLogin(user);
    }
    setLoading(false);
  };

  const inp=(label,type,key,ph)=>(
    <div style={{marginBottom:12}}>
      <label style={{display:"block",fontSize:11,color:"var(--azure)",fontWeight:700,letterSpacing:1,marginBottom:5,textTransform:"uppercase"}}>{label}</label>
      <input type={type} value={f[key]} onChange={e=>setF(p=>({...p,[key]:e.target.value}))} placeholder={ph}
        style={{width:"100%",padding:"11px 14px",background:"rgba(23,45,105,.6)",border:"1px solid rgba(65,161,231,.25)",borderRadius:8,color:"var(--text)",fontSize:14}}
        onKeyDown={e=>e.key==="Enter"&&submit()}/>
    </div>
  );

  return(
    <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:20,background:"var(--bg)",position:"relative",overflow:"hidden"}}>
      <G/>
      <div style={{position:"absolute",inset:0,pointerEvents:"none"}}>
        <div style={{position:"absolute",width:400,height:400,borderRadius:"50%",background:"radial-gradient(circle,rgba(4,103,172,.2) 0%,transparent 70%)",top:"-10%",left:"-10%",animation:"blob1 8s ease-in-out infinite"}}/>
        <div style={{position:"absolute",width:300,height:300,borderRadius:"50%",background:"radial-gradient(circle,rgba(57,255,20,.06) 0%,transparent 70%)",bottom:"5%",right:"5%",animation:"blob2 10s ease-in-out infinite"}}/>
      </div>
      <div style={{position:"relative",zIndex:1,textAlign:"center",marginBottom:24}}>
        <img src={LOGO_S} alt="AESMSL" style={{height:70,filter:"drop-shadow(0 0 20px rgba(65,161,231,.4))"}}/>
        <div style={{fontFamily:"Anton,sans-serif",fontSize:13,letterSpacing:4,color:"var(--azure)",marginTop:8}}>WORLD CUP 2026 · PREDICTIONS</div>
      </div>
      <div style={{position:"relative",zIndex:1,marginBottom:14,width:"100%",maxWidth:420,padding:"12px 16px",background:"rgba(57,255,20,.07)",border:"1px solid rgba(57,255,20,.25)",borderRadius:12,display:"flex",alignItems:"center",gap:10}}>
        <span style={{fontSize:20}}>⏰</span>
        <div>
          <div style={{fontWeight:700,color:"var(--green)",fontSize:13}}>Deadline: June 11, 2026 at 6:00 PM</div>
          <div style={{fontSize:11,color:"var(--muted)",marginTop:2}}>Swiss time · Predictions locked at kick-off</div>
        </div>
      </div>
      <div style={{position:"relative",zIndex:1,width:"100%",maxWidth:420,background:"rgba(23,45,105,.7)",border:"1px solid rgba(65,161,231,.2)",borderRadius:16,padding:32,backdropFilter:"blur(20px)"}}>
        <div style={{display:"flex",marginBottom:20,background:"rgba(0,0,0,.3)",borderRadius:10,overflow:"hidden"}}>
          {["login","register"].map(m=>(
            <button key={m} onClick={()=>{setMode(m);setErr("");}}
              style={{flex:1,padding:"11px 0",border:"none",background:mode===m?"linear-gradient(135deg,var(--blue),var(--azure))":"transparent",color:"#fff",fontWeight:700,opacity:mode===m?1:.5,transition:"all .2s"}}>
              {m==="login"?"LOG IN":"SIGN UP"}
            </button>
          ))}
        </div>
        {mode==="register"&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>{inp("First name","text","prenom","First name")}{inp("Last name","text","nom","Last name")}</div>}
        {inp("Email","email","email","firstname.lastname@example.com")}
        {inp("Password","password","pw","••••••••")}
        {mode==="register"&&inp("Confirm password","password","pw2","••••••••")}
        {err&&<div style={{color:"#ff6b6b",fontSize:12,marginBottom:12,padding:"8px 12px",background:"rgba(255,100,100,.1)",borderRadius:6}}>{err}</div>}
        <button onClick={submit} disabled={loading}
          style={{width:"100%",padding:"12px 0",background:"linear-gradient(135deg,var(--blue),var(--azure))",border:"none",borderRadius:8,color:"#fff",fontWeight:700,fontSize:15,opacity:loading?.7:1}}>
          {loading?"...":(mode==="login"?"LOG IN":"CREATE ACCOUNT")}
        </button>
      </div>
      <div style={{marginTop:14,fontSize:11,color:"rgba(255,255,255,.2)",zIndex:1}}>Student Association · Sports Management School Lausanne</div>
    </div>
  );
}

// ─── LEADERBOARD ──────────────────────────────────────────────────────────────
function Leaderboard({uid,results}){
  const [entries,setEntries]=useState([]);
  const [loading,setLoading]=useState(true);
  useEffect(()=>{
    const unsub=onSnapshot(collection(db,"pronostics"),async snap=>{
      const pronos={};snap.docs.forEach(d=>{pronos[d.id]=d.data();});
      try{
        const [uSnap,res]=await Promise.all([getDocs(collection(db,"users")),fbGetResults()]);
        const list=uSnap.docs.map(d=>d.data()).filter(u=>!u.isAdmin).map(u=>({
          id:u.id,name:`${u.prenom} ${u.nom}`,pts:calcPoints(pronos[u.id],res||results),submitted:!!pronos[u.id]
        })).sort((a,b)=>b.pts-a.pts);
        setEntries(list);setLoading(false);
      }catch{setLoading(false);}
    });
    return()=>unsub();
  },[results]);
  if(loading) return <Spinner/>;
  const medals=["🥇","🥈","🥉"],colors=["#c0c0c0","#ffd700","#cd7f32"];
  return(
    <div>
      <STitle icon="🏅" title="LEADERBOARD" sub="Updated in real time"/>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12,marginBottom:20}}>
        {[{l:"Participants",v:entries.length,i:"👥",c:"var(--azure)"},{l:"Submitted",v:entries.filter(e=>e.submitted).length,i:"📝",c:"var(--green)"},{l:"Top score",v:entries[0]?.pts||0,i:"⭐",c:"var(--purple)"}].map(({l,v,i,c})=>(
          <div key={l} style={{background:"rgba(23,45,105,.6)",border:`1px solid ${c}33`,borderRadius:12,padding:16,textAlign:"center"}}>
            <div style={{fontSize:22,marginBottom:4}}>{i}</div>
            <div style={{fontFamily:"Anton,sans-serif",fontSize:26,color:c}}>{v}</div>
            <div style={{fontSize:10,color:"var(--muted)",letterSpacing:1,marginTop:2}}>{l.toUpperCase()}</div>
          </div>
        ))}
      </div>
      {entries.length>=3&&(
        <div style={{display:"grid",gridTemplateColumns:"1fr 1.1fr 1fr",gap:8,marginBottom:16}}>
          {[entries[1],entries[0],entries[2]].map((e,i)=>{
            const rank=i===1?0:i===0?1:2,h=[80,100,70][rank],c=colors[rank];
            return e?(<div key={e.id} style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"flex-end"}}>
              <div style={{fontSize:12,fontWeight:600,color:"rgba(255,255,255,.7)",marginBottom:3,textAlign:"center"}}>{e.name}</div>
              <div style={{fontFamily:"Anton,sans-serif",fontSize:16,color:c,marginBottom:3}}>{e.pts} pts</div>
              <div style={{width:"100%",height:h,background:`linear-gradient(180deg,${c}33,${c}11)`,border:`1px solid ${c}66`,borderRadius:"8px 8px 0 0",display:"flex",alignItems:"center",justifyContent:"center",fontSize:26}}>{medals[rank]}</div>
            </div>):<div key={i}/>;
          })}
        </div>
      )}
      <div style={{background:"rgba(23,45,105,.5)",border:"1px solid rgba(65,161,231,.15)",borderRadius:12,overflow:"hidden"}}>
        <div style={{display:"grid",gridTemplateColumns:"44px 1fr auto",padding:"10px 16px",background:"rgba(4,103,172,.3)",borderBottom:"1px solid rgba(65,161,231,.15)"}}>
          {["#","PARTICIPANT","PTS"].map(h=><span key={h} style={{fontSize:10,letterSpacing:2,color:"var(--azure)",fontWeight:700,textAlign:h==="PTS"?"right":"left"}}>{h}</span>)}
        </div>
        {entries.length===0&&<div style={{padding:40,textAlign:"center",color:"var(--muted)"}}>No participants yet. Be the first! 🎉</div>}
        {entries.map((e,i)=>(
          <div key={e.id} style={{display:"grid",gridTemplateColumns:"44px 1fr auto",padding:"13px 16px",alignItems:"center",background:e.id===uid?"rgba(57,255,20,.06)":"transparent",borderBottom:i<entries.length-1?"1px solid rgba(255,255,255,.04)":"none",borderLeft:e.id===uid?"3px solid var(--green)":"3px solid transparent"}}>
            <div style={{fontFamily:"Anton,sans-serif",fontSize:18,color:i===0?"#ffd700":i===1?"#c0c0c0":i===2?"#cd7f32":"rgba(255,255,255,.2)"}}>{i<3?medals[i]:i+1}</div>
            <div>
              <span style={{fontWeight:600,color:e.id===uid?"var(--green)":"var(--text)"}}>{e.name}</span>
              {e.id===uid&&<span style={{marginLeft:6,fontSize:10,background:"var(--green)",color:"#0a1a0a",borderRadius:4,padding:"1px 5px",fontWeight:700}}>YOU</span>}
              {!e.submitted&&<div style={{fontSize:11,color:"#ff8c42"}}>⏳ Predictions not submitted</div>}
            </div>
            <div style={{fontFamily:"Anton,sans-serif",fontSize:22,color:"var(--azure)",textAlign:"right"}}>{e.pts}</div>
          </div>
        ))}
      </div>
      <div style={{marginTop:12,padding:"10px 14px",background:"rgba(255,255,255,.02)",border:"1px solid rgba(255,255,255,.06)",borderRadius:10,fontSize:11,color:"var(--muted)"}}>
        <strong style={{color:"rgba(255,255,255,.5)"}}>Scoring:</strong>{" "}
        {[["Exact score",5],["Correct result",2],["KO qualifier",3],["Champion",10],["Top scorer",8],["Dark horse",5]].map(([l,v])=>(
          <span key={l} style={{marginRight:14}}><span style={{color:"var(--azure)",fontWeight:700}}>{v}pts</span> {l}</span>
        ))}
      </div>
    </div>
  );
}

// ─── PREDICTIONS VIEW ─────────────────────────────────────────────────────────
function PredictionsView({user}){
  const [step,setStep]=useState(1); // 1=groups+3rds, 2=bracket, 3=bonus
  const [p,setP]=useState(null);
  const [grp,setGrp]=useState("A");
  const [saving,setSaving]=useState(false);
  const [saved,setSaved]=useState(false);
  const [loading,setLoading]=useState(true);
  const EMPTY={groupScores:{},knockout:{r32:{},r16:{},qf:{},sf:{},final:{}},thirds8:[],champion:null,championOther:"",topScorer:null,topScorerOther:"",darkHorse:null};

  useEffect(()=>{fbGetPronos(user.id).then(data=>{setP(data||EMPTY);setLoading(false);});},[ user.id]);
  const upd=fn=>setP(prev=>{const n=JSON.parse(JSON.stringify(prev));fn(n);return n;});
  const save=async()=>{
    if(isLocked()) return;
    setSaving(true);
    await fbSetPronos(user.id,{...p,savedAt:Date.now()});
    setSaving(false);setSaved(true);
    setTimeout(()=>setSaved(false),2500);
  };

  if(loading) return <Spinner/>;

  const groupsDone=allGroupsFilled(p.groupScores);
  const groupsPct=getGroupPct(p.groupScores);
  const thirds8 = p.thirds8 || [];
  const thirds8Done = thirds8.length === 8;
  const step1Done = groupsDone && thirds8Done;

  const getKO=id=>{for(const r of ["r32","r16","qf","sf","final"]) if(p.knockout?.[r]?.[id]) return p.knockout[r][id];return null;};
  const r32=buildR32(p.groupScores, p.thirds8||[]);
  const r16=[["r32-1","r32-2"],["r32-3","r32-4"],["r32-5","r32-6"],["r32-7","r32-8"],["r32-9","r32-10"],["r32-11","r32-12"],["r32-13","r32-14"],["r32-15","r32-16"]].map(([a,b],i)=>({id:`r16-${i+1}`,home:getKO(a)||"?",away:getKO(b)||"?"}));
  const qf=[["r16-1","r16-2"],["r16-3","r16-4"],["r16-5","r16-6"],["r16-7","r16-8"]].map(([a,b],i)=>({id:`qf-${i+1}`,home:getKO(a)||"?",away:getKO(b)||"?"}));
  const sf=[["qf-1","qf-2"],["qf-3","qf-4"]].map(([a,b],i)=>({id:`sf-${i+1}`,home:getKO(a)||"?",away:getKO(b)||"?"}));
  const fin=[{id:"final-1",home:getKO("sf-1")||"?",away:getKO("sf-2")||"?"}];

  const setKO=(mid,team,round)=>upd(pr=>{pr.knockout[round]=pr.knockout[round]||{};pr.knockout[round][mid]=team;});

  const KOCard=({match,round})=>{
    const picked=p.knockout?.[round]?.[match.id];
    return(
      <div style={{background:"rgba(23,45,105,.6)",border:"1px solid rgba(65,161,231,.15)",borderRadius:10,overflow:"hidden"}}>
        {[match.home,match.away].map((team,idx)=>{
          const isW=picked===team,isQ=team!=="?"&&team!=="3rd TBD"&&team!=="3rd place TBD"&&!isLocked();
          return(<div key={idx} className={isQ?"ph":""} onClick={()=>isQ&&setKO(match.id,team,round)}
            style={{padding:"9px 14px",display:"flex",alignItems:"center",gap:8,background:isW?"rgba(57,255,20,.12)":"transparent",borderBottom:idx===0?"1px solid rgba(255,255,255,.06)":"none",cursor:isQ?"pointer":"default",opacity:(team==="?"||team==="3rd TBD")?.3:1,transition:"background .15s"}}>
            <span style={{fontSize:10,width:14}}>{isW?"✅":""}</span>
            <span style={{fontSize:12,color:isW?"var(--green)":"var(--text)",fontWeight:isW?700:400,flex:1}}>{team}</span>
          </div>);
        })}
      </div>
    );
  };

  const BonusOpt=({selected,onClick,children})=>(<div onClick={isLocked()?null:onClick} className={isLocked()?"":"ch"}
    style={{padding:"8px 12px",marginBottom:5,borderRadius:8,cursor:isLocked()?"default":"pointer",background:selected?"rgba(57,255,20,.15)":"rgba(23,45,105,.4)",border:selected?"1px solid var(--green)":"1px solid rgba(65,161,231,.15)",color:selected?"var(--green)":"var(--text)",fontWeight:selected?700:400,fontSize:13,transition:"all .15s"}}>
    {selected&&"✅ "}{children}
  </div>);

  const OtherInput=({label,fieldKey,otherKey,pts})=>(
    <div style={{marginTop:10,padding:"12px 14px",background:"rgba(23,45,105,.5)",border:"1px solid rgba(65,161,231,.2)",borderRadius:10}}>
      <div style={{fontSize:12,color:"var(--azure)",fontWeight:700,marginBottom:8}}>🔍 Other {label} not listed <span style={{color:"var(--green)",marginLeft:4}}>+{pts}pts</span></div>
      <div style={{display:"flex",gap:8,alignItems:"center"}}>
        <input value={p[otherKey]||""} onChange={e=>!isLocked()&&upd(pr=>{pr[otherKey]=e.target.value;})} placeholder={`Type ${label.toLowerCase()} name...`} disabled={isLocked()}
          style={{flex:1,padding:"9px 12px",background:"rgba(255,255,255,.08)",border:"1px solid rgba(65,161,231,.3)",borderRadius:7,color:"var(--text)",fontSize:13}}/>
        <button onClick={()=>!isLocked()&&upd(pr=>{pr[fieldKey]="__other__";})} disabled={isLocked()}
          style={{padding:"9px 14px",background:p[fieldKey]==="__other__"?"rgba(57,255,20,.2)":"rgba(65,161,231,.15)",border:p[fieldKey]==="__other__"?"1px solid var(--green)":"1px solid rgba(65,161,231,.3)",borderRadius:7,color:p[fieldKey]==="__other__"?"var(--green)":"var(--azure)",fontWeight:700,fontSize:12,whiteSpace:"nowrap"}}>
          {p[fieldKey]==="__other__"?"✅ Selected":"Choose"}
        </button>
      </div>
    </div>
  );

  const BonusCard=({icon,title,sub,pts,children})=>(
    <div style={{background:"rgba(23,45,105,.6)",border:"1px solid rgba(65,161,231,.2)",borderRadius:14,overflow:"hidden"}}>
      <div style={{padding:"14px 18px",borderBottom:"1px solid rgba(65,161,231,.1)",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
        <div><div style={{fontFamily:"Anton,sans-serif",fontSize:18,letterSpacing:2,color:"var(--azure)"}}>{icon} {title}</div><div style={{fontSize:12,color:"var(--muted)",marginTop:3}}>{sub}</div></div>
        <div style={{textAlign:"center"}}><div style={{fontFamily:"Anton,sans-serif",fontSize:26,color:"var(--green)"}}>{pts}</div><div style={{fontSize:10,color:"var(--muted)"}}>PTS</div></div>
      </div>
      <div style={{padding:16,maxHeight:360,overflowY:"auto"}}>{children}</div>
    </div>
  );

  const filledG=GROUP_MATCHES.filter(m=>{const s=p.groupScores?.[m.id];return s&&s.h!=null&&s.a!=null;}).length;
  const progress=Math.round(((filledG+(p.champion?1:0)+(p.topScorer?1:0)+(p.darkHorse?1:0)+(groupsDone?1:0))/(GROUP_MATCHES.length+4))*100);

  // Step indicator
  const steps=[{n:1,l:"Groups & 3rd place"},{n:2,l:"Knockout"},{n:3,l:"Bonus"}];

  return(
    <div>
      {/* Header */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,flexWrap:"wrap",gap:12}}>
        <div>
          <div style={{fontFamily:"Anton,sans-serif",fontSize:22,letterSpacing:3,color:"var(--azure)",display:"flex",alignItems:"center",gap:8}}>📝 MY PREDICTIONS</div>
          <div style={{fontSize:12,color:"var(--muted)",marginTop:4}}>Deadline: June 11, 2026 at 6:00 PM Swiss time</div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <div>
            <div style={{fontSize:10,color:"var(--muted)",letterSpacing:1,marginBottom:3}}>COMPLETION</div>
            <div style={{display:"flex",alignItems:"center",gap:8}}>
              <div style={{width:100,height:6,background:"rgba(255,255,255,.08)",borderRadius:3,overflow:"hidden"}}>
                <div style={{width:`${progress}%`,height:"100%",background:"linear-gradient(90deg,var(--blue),var(--green))",borderRadius:3,transition:"width .4s"}}/>
              </div>
              <span style={{fontFamily:"Anton,sans-serif",fontSize:16,color:"var(--green)"}}>{progress}%</span>
            </div>
          </div>
          <button onClick={save} disabled={saving||isLocked()}
            style={{padding:"11px 20px",background:isLocked()?"rgba(255,255,255,.1)":saved?"#1a5c1a":"linear-gradient(135deg,var(--blue),var(--azure))",border:isLocked()?"1px solid rgba(255,255,255,.1)":"none",borderRadius:8,color:isLocked()?"rgba(255,255,255,.3)":"#fff",fontWeight:700,minWidth:140,transition:"all .3s",cursor:isLocked()?"not-allowed":"pointer"}}>
            {isLocked()?"🔒 LOCKED":saving?"...":saved?"✓ SAVED":"💾 SAVE"}
          </button>
        </div>
      </div>

      {/* Lock / countdown banner */}
      {isLocked()?(
        <div style={{marginBottom:16,padding:"14px 18px",background:"rgba(255,80,80,.1)",border:"1px solid rgba(255,80,80,.3)",borderRadius:10,display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontSize:20}}>🔒</span>
          <div><div style={{fontWeight:700,color:"#ff8888",fontSize:14}}>Predictions locked</div><div style={{fontSize:12,color:"var(--muted)",marginTop:2}}>The competition has started.</div></div>
        </div>
      ):timeLeft()&&(
        <div style={{marginBottom:16,padding:"12px 16px",background:"rgba(57,255,20,.06)",border:"1px solid rgba(57,255,20,.2)",borderRadius:10,display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontSize:18}}>⏰</span>
          <div style={{fontSize:13,color:"var(--green)"}}><strong>Deadline in {timeLeft()}</strong><span style={{color:"var(--muted)",marginLeft:6}}>· June 11 at 6:00 PM Swiss time</span></div>
        </div>
      )}

      {/* Step indicator */}
      <div style={{display:"flex",gap:0,marginBottom:24,background:"rgba(0,0,0,.3)",borderRadius:12,overflow:"hidden"}}>
        {steps.map((s,i)=>{
          const done=(s.n===1&&step1Done)||(s.n===2&&step>=2)||(s.n===3&&step>=3);
          const active=step===s.n;
          return(
            <button key={s.n} onClick={()=>{if(s.n===1||step1Done) setStep(s.n);}}
              style={{flex:1,padding:"12px 8px",border:"none",borderRight:i<2?"1px solid rgba(255,255,255,.08)":"none",
                background:active?"linear-gradient(135deg,var(--blue),var(--azure))":"transparent",
                color:active?"#fff":done?"var(--green)":"var(--muted)",fontWeight:600,fontSize:13,
                cursor:(s.n===1||step1Done)?"pointer":"not-allowed",transition:"all .2s",
                opacity:(s.n>1&&!step1Done&&!active)?.4:1}}>
              <span style={{marginRight:6}}>{done&&!active?"✅":s.n===1?"⚽":s.n===2?"🏆":"🎯"}</span>
              {s.n===1?"Groups & 3rds":s.n===2?"Knockout":"Bonus"}
            </button>
          );
        })}
      </div>

      {/* ═══ STEP 1: GROUPS + 3RD PLACE SELECTION ═══ */}
      {step===1&&(
        <div>
          {/* Group selector */}
          <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:16}}>
            {Object.keys(GROUPS).map(g=>{
              const filled=GROUP_MATCHES.filter(m=>m.group===g&&p.groupScores?.[m.id]?.h!=null).length;
              const total=GROUP_MATCHES.filter(m=>m.group===g).length;
              return(<button key={g} onClick={()=>setGrp(g)}
                style={{padding:"6px 14px",border:grp===g?"1px solid var(--azure)":"1px solid rgba(65,161,231,.2)",borderRadius:7,background:grp===g?"rgba(65,161,231,.2)":"rgba(23,45,105,.4)",color:grp===g?"var(--azure)":"var(--muted)",fontWeight:600,transition:"all .15s"}}>
                GR.{g} {filled===total&&total>0?"✅":""}
              </button>);
            })}
          </div>

          {/* Matches + standings */}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:24}}>
            <div>
              <div style={{fontSize:11,fontWeight:700,letterSpacing:2,color:"var(--azure)",marginBottom:10}}>MATCHES — GROUP {grp}</div>
              {GROUP_MATCHES.filter(m=>m.group===grp).map(m=>{
                const s=p.groupScores?.[m.id]||{},done=s.h!=null&&s.a!=null;
                return(<div key={m.id} style={{background:done?"rgba(57,255,20,.05)":"rgba(23,45,105,.4)",border:done?"1px solid rgba(57,255,20,.2)":"1px solid rgba(65,161,231,.15)",borderRadius:10,padding:"10px 14px",display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
                  <span style={{flex:1,fontSize:12,textAlign:"right",color:"#ccc"}}>{m.home}</span>
                  <ScoreInp value={s.h} onChange={v=>upd(pr=>{pr.groupScores[m.id]=pr.groupScores[m.id]||{};pr.groupScores[m.id].h=v;})}/>
                  <span style={{color:"var(--muted)",fontSize:11}}>–</span>
                  <ScoreInp value={s.a} onChange={v=>upd(pr=>{pr.groupScores[m.id]=pr.groupScores[m.id]||{};pr.groupScores[m.id].a=v;})}/>
                  <span style={{flex:1,fontSize:12,color:"#ccc"}}>{m.away}</span>
                </div>);
              })}
            </div>
            <div>
              <div style={{fontSize:11,fontWeight:700,letterSpacing:2,color:"var(--azure)",marginBottom:10}}>PREDICTED STANDINGS</div>
              <div style={{background:"rgba(23,45,105,.4)",border:"1px solid rgba(65,161,231,.15)",borderRadius:10,overflow:"hidden"}}>
                <div style={{display:"grid",gridTemplateColumns:"24px 1fr 28px 28px 28px 28px 32px",gap:4,padding:"8px 12px",background:"rgba(4,103,172,.2)",borderBottom:"1px solid rgba(65,161,231,.1)"}}>
                  {["","Team","P","GF","GA","GD","Pts"].map((h,i)=><span key={i} style={{fontSize:10,color:"var(--azure)",fontWeight:700,letterSpacing:1,textAlign:i>1?"center":"left"}}>{h}</span>)}
                </div>
                {computeStandings(grp,p.groupScores).map((r,i)=>(
                  <div key={r.team} style={{display:"grid",gridTemplateColumns:"24px 1fr 28px 28px 28px 28px 32px",gap:4,padding:"10px 12px",alignItems:"center",background:i<2?"rgba(65,161,231,.05)":i===2?"rgba(143,0,255,.04)":"transparent",borderBottom:i<3?"1px solid rgba(255,255,255,.04)":"none"}}>
                    <span style={{fontFamily:"Anton,sans-serif",fontSize:13,color:i===0?"#ffd700":i===1?"#c0c0c0":i===2?"var(--purple)":"#444"}}>{i===0?"🥇":i===1?"🥈":i===2?"🔵":i+1}</span>
                    <span style={{fontSize:11,color:"#ccc"}}>{r.team}</span>
                    {[r.pl,r.gf,r.ga].map((v,k)=><span key={k} style={{textAlign:"center",fontSize:11,color:"#666"}}>{v}</span>)}
                    <span style={{textAlign:"center",fontSize:11,color:r.gd>0?"var(--green)":r.gd<0?"#ff6b6b":"#666"}}>{r.gd>0?`+${r.gd}`:r.gd}</span>
                    <span style={{textAlign:"center",fontFamily:"Anton,sans-serif",fontSize:16,color:"var(--azure)"}}>{r.pts}</span>
                  </div>
                ))}
              </div>
              <div style={{marginTop:8,fontSize:11,color:"var(--muted)"}}>🥇🥈 Auto qualified · 🔵 Possible best 3rd</div>
            </div>
          </div>



          {/* Best 8 thirds preview */}
          {groupsDone&&(()=>{
            const allT=Object.keys(GROUPS).map(g=>{const st=computeStandings(g,p.groupScores);return st[2]?{...st[2],group:g}:null;}).filter(Boolean).sort((a,b)=>b.pts-a.pts||b.gd-a.gd||b.gf-a.gf);
            const best8=allT.slice(0,8);
            const eliminated=allT.slice(8);
            return(
              <div style={{marginBottom:20,padding:16,background:"rgba(23,45,105,.5)",border:"1px solid rgba(65,161,231,.2)",borderRadius:12}}>
                <div style={{fontFamily:"Anton,sans-serif",fontSize:15,letterSpacing:2,color:"var(--azure)",marginBottom:12}}>🔵 AUTO-QUALIFIED 3RD PLACE TEAMS</div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8,marginBottom:12}}>
                  {best8.map((t,i)=>(
                    <div key={t.group} style={{padding:"10px 12px",background:"rgba(57,255,20,.1)",border:"1px solid rgba(57,255,20,.3)",borderRadius:8}}>
                      <div style={{fontSize:10,color:"var(--green)",letterSpacing:1,marginBottom:3}}>GR.{t.group} · #{i+1}</div>
                      <div style={{fontSize:12,color:"#fff",fontWeight:600,marginBottom:3}}>{t.team}</div>
                      <div style={{display:"flex",gap:6}}>
                        <span style={{fontSize:10,color:"var(--muted)"}}>{t.pts}pts</span>
                        <span style={{fontSize:10,color:t.gd>=0?"var(--green)":"#ff6b6b"}}>{t.gd>0?"+":""}{t.gd}GD</span>
                      </div>
                    </div>
                  ))}
                </div>
                {eliminated.length>0&&(
                  <div>
                    <div style={{fontSize:11,color:"var(--muted)",marginBottom:6,letterSpacing:1}}>❌ ELIMINATED 3RDS</div>
                    <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                      {eliminated.map(t=>(
                        <div key={t.group} style={{padding:"6px 10px",background:"rgba(255,100,100,.08)",border:"1px solid rgba(255,100,100,.2)",borderRadius:6,fontSize:11,color:"#888"}}>
                          GR.{t.group} · {t.team} · {t.pts}pts
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            );
          })()}

          {/* 3rd place selector */}
          <div style={{marginBottom:20,padding:20,background:"rgba(23,45,105,.6)",border:"1px solid rgba(65,161,231,.25)",borderRadius:14}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
              <div>
                <div style={{fontFamily:"Anton,sans-serif",fontSize:17,letterSpacing:2,color:"var(--azure)"}}>🔵 SELECT THE 8 BEST 3RD-PLACE TEAMS</div>
                <div style={{fontSize:11,color:"var(--muted)",marginTop:3}}>Pick exactly 8 out of 12 · They face group winners in the R32</div>
              </div>
              <div style={{textAlign:"center"}}>
                <div style={{fontFamily:"Anton,sans-serif",fontSize:28,color:thirds8Done?"var(--green)":"#ff8c42"}}>{thirds8.length}/8</div>
                <div style={{fontSize:10,color:"var(--muted)"}}>SELECTED</div>
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10}}>
              {Object.keys(GROUPS).map(g => {
                const st = computeStandings(g, p.groupScores);
                const third = st[2];
                const isSelected = thirds8.some(t => t.group === g);
                const canSelect = thirds8.length < 8 || isSelected;
                if (!third) return (
                  <div key={g} style={{padding:"12px",background:"rgba(255,255,255,.03)",borderRadius:8,border:"1px solid rgba(255,255,255,.06)",opacity:.5}}>
                    <div style={{fontSize:10,color:"var(--muted)",marginBottom:4}}>GROUP {g}</div>
                    <div style={{fontSize:11,color:"#555"}}>Fill scores first</div>
                  </div>
                );
                return (
                  <div key={g} onClick={() => {
                    if (isLocked()) return;
                    upd(pr => {
                      pr.thirds8 = pr.thirds8 || [];
                      if (isSelected) pr.thirds8 = pr.thirds8.filter(t => t.group !== g);
                      else if (pr.thirds8.length < 8) pr.thirds8.push({group:g, team:third.team, pts:third.pts, gd:third.gd, gf:third.gf});
                    });
                  }} style={{
                    padding:"12px 14px", borderRadius:10, cursor:(isLocked()||(!canSelect&&!isSelected))?"default":"pointer",
                    background:isSelected?"rgba(57,255,20,.15)":"rgba(255,255,255,.04)",
                    border:isSelected?"1px solid var(--green)":"1px solid rgba(65,161,231,.15)",
                    opacity:(!canSelect&&!isSelected)?.4:1, transition:"all .15s"
                  }}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
                      <span style={{fontSize:10,letterSpacing:1,color:isSelected?"var(--green)":"var(--muted)",fontWeight:700}}>GRP {g}</span>
                      {isSelected && <span>✅</span>}
                    </div>
                    <div style={{fontSize:12,color:isSelected?"var(--green)":"var(--text)",fontWeight:isSelected?700:400,marginBottom:5}}>{third.team}</div>
                    <div style={{display:"flex",gap:6}}>
                      <span style={{fontSize:10,background:"rgba(255,255,255,.08)",padding:"2px 6px",borderRadius:4,color:"var(--muted)"}}>{third.pts}pts</span>
                      <span style={{fontSize:10,background:"rgba(255,255,255,.08)",padding:"2px 6px",borderRadius:4,color:third.gd>=0?"var(--green)":"#ff6b6b"}}>{third.gd>=0?"+":""}{third.gd}GD</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Validate button */}
          <div style={{textAlign:"center",padding:"20px 0"}}>
            {!groupsDone&&(
              <div style={{marginBottom:12,fontSize:13,color:"#ffb800"}}>⚠️ Complete all group scores first ({groupsPct}% done)</div>
            )}
            {groupsDone && !thirds8Done && (
              <div style={{marginBottom:12,fontSize:13,color:"#ffb800"}}>⚠️ Select {8-thirds8.length} more 3rd-place team{8-thirds8.length>1?"s":""}</div>
            )}

            <button onClick={()=>{if(step1Done){save();setStep(2);}}} disabled={!step1Done||isLocked()}
              style={{padding:"14px 48px",background:step1Done?"linear-gradient(135deg,var(--blue),var(--azure))":"rgba(255,255,255,.1)",border:"none",borderRadius:10,color:step1Done?"#fff":"rgba(255,255,255,.3)",fontWeight:700,fontSize:16,cursor:step1Done&&!isLocked()?"pointer":"not-allowed",letterSpacing:1,transition:"all .3s",boxShadow:step1Done?"0 4px 20px rgba(65,161,231,.3)":"none"}}>
              {!groupsDone?`Complete groups first (${groupsPct}%)`:!thirds8Done?`Select ${8-thirds8.length} more 3rd(s)`:"✅ VALIDATE & CONTINUE →"}
            </button>
          </div>
        </div>
      )}

      {/* ═══ STEP 2: KNOCKOUT BRACKET ═══ */}
      {step===2&&(
        <div>
          <div style={{marginBottom:16,padding:"12px 16px",background:"rgba(65,161,231,.05)",border:"1px solid rgba(65,161,231,.15)",borderRadius:10,fontSize:12,color:"rgba(65,161,231,.8)"}}>
            💡 Click the winning team to advance them to the next round.
          </div>
          {[{label:"ROUND OF 32",matches:r32,round:"r32",cols:4},{label:"ROUND OF 16",matches:r16,round:"r16",cols:4},{label:"QUARTER-FINALS",matches:qf,round:"qf",cols:2},{label:"SEMI-FINALS",matches:sf,round:"sf",cols:2},{label:"🏆 FINAL",matches:fin,round:"final",cols:1}].map(({label,matches,round,cols})=>(
            <div key={round} style={{marginBottom:24}}>
              <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
                <div style={{flex:1,height:1,background:"rgba(65,161,231,.2)"}}/>
                <span style={{fontFamily:"Anton,sans-serif",fontSize:13,letterSpacing:2,color:"var(--azure)"}}>{label}</span>
                <div style={{flex:1,height:1,background:"rgba(65,161,231,.2)"}}/>
              </div>
              <div style={{display:"grid",gridTemplateColumns:`repeat(${Math.min(cols,matches.length)},1fr)`,gap:8}}>
                {matches.map(m=><KOCard key={m.id} match={m} round={round}/>)}
              </div>
            </div>
          ))}
          <div style={{textAlign:"center",padding:"20px 0"}}>
            <button onClick={()=>{save();setStep(3);}}
              style={{padding:"14px 48px",background:"linear-gradient(135deg,var(--blue),var(--azure))",border:"none",borderRadius:10,color:"#fff",fontWeight:700,fontSize:16,cursor:"pointer",letterSpacing:1,boxShadow:"0 4px 20px rgba(65,161,231,.3)"}}>
              CONTINUE TO BONUS →
            </button>
          </div>
        </div>
      )}

      {/* ═══ STEP 3: BONUS ═══ */}
      {step===3&&(
        <div style={{display:"flex",flexDirection:"column",gap:20}}>
          <BonusCard icon="🏆" title="WORLD CHAMPION" sub="Which team will lift the trophy on July 19?" pts={POINTS.champion}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
              {Object.entries(GROUPS).map(([g,teams])=>(
                <div key={g}><div style={{fontSize:10,color:"var(--azure)",marginBottom:4,letterSpacing:1}}>GR.{g}</div>
                  {teams.map(t=><BonusOpt key={t} selected={p.champion===t} onClick={()=>upd(pr=>{pr.champion=t;})}>{t}</BonusOpt>)}
                </div>
              ))}
            </div>
            <OtherInput label="team" fieldKey="champion" otherKey="championOther" pts={POINTS.champion}/>
          </BonusCard>
          <BonusCard icon="⚡" title="TOP SCORER" sub="Who will finish as the tournament's top scorer?" pts={POINTS.topScorer}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:8}}>
              {TOP_SCORERS.map(pl=><BonusOpt key={pl} selected={p.topScorer===pl&&p.topScorer!=="__other__"} onClick={()=>upd(pr=>{pr.topScorer=pl;})}>{pl}</BonusOpt>)}
            </div>
            <OtherInput label="player" fieldKey="topScorer" otherKey="topScorerOther" pts={POINTS.topScorer}/>
          </BonusCard>
          <BonusCard icon="🐴" title="DARK HORSE" sub="Which outsider will reach the quarter-finals or beyond?" pts={POINTS.darkHorse}>
            <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:8}}>
              {DARK_HORSE_TEAMS.map(t=><BonusOpt key={t} selected={p.darkHorse===t} onClick={()=>upd(pr=>{pr.darkHorse=t;})}>{t}</BonusOpt>)}
            </div>
          </BonusCard>
          <div style={{textAlign:"center",padding:"10px 0"}}>
            <button onClick={save} disabled={saving||isLocked()}
              style={{padding:"14px 48px",background:saved?"#1a5c1a":"linear-gradient(135deg,var(--blue),var(--azure))",border:"none",borderRadius:10,color:"#fff",fontWeight:700,fontSize:16,cursor:isLocked()?"not-allowed":"pointer",letterSpacing:1}}>
              {isLocked()?"🔒 LOCKED":saving?"...":saved?"✓ ALL SAVED !":"💾 SAVE ALL PREDICTIONS"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── ADMIN VIEW ────────────────────────────────────────────────────────────────
function AdminView({onResultsChange}){
  const [res,setRes]=useState(null);
  const [loading,setLoading]=useState(true);
  const [saving,setSaving]=useState(false);
  const [saved,setSaved]=useState(false);
  const [tab,setTab]=useState("stats");
  const [grp,setGrp]=useState("A");
  const [users,setUsers]=useState([]);
  const [pronos,setPronos]=useState({});

  useEffect(()=>{
    Promise.all([fbGetResults(),getDocs(collection(db,"users")),getDocs(collection(db,"pronostics"))]).then(([r,uSnap,pSnap])=>{
      setRes(r||{groupScores:{},knockout:{r32:{},r16:{},qf:{},sf:{},final:{}},champion:"",topScorer:"",darkHorse:""});
      setUsers(uSnap.docs.map(d=>d.data()).filter(u=>!u.isAdmin));
      const pm={};pSnap.docs.forEach(d=>{pm[d.id]=d.data();});setPronos(pm);setLoading(false);
    });
  },[]);

  const saveRes=async()=>{setSaving(true);await fbSetResults(res);setSaving(false);setSaved(true);onResultsChange&&onResultsChange(res);setTimeout(()=>setSaved(false),2000);};
  const updR=fn=>setRes(prev=>{const n=JSON.parse(JSON.stringify(prev));fn(n);return n;});
  if(loading) return <Spinner/>;
  const scoreboard=users.map(u=>({...u,pts:calcPoints(pronos[u.id],res),submitted:!!pronos[u.id]})).sort((a,b)=>b.pts-a.pts);

  return(
    <div>
      <STitle icon="⚙️" title="ADMIN PANEL" sub="Enter real results to update the live leaderboard"/>
      <div style={{marginBottom:20,padding:"10px 14px",background:"rgba(255,80,80,.08)",border:"1px solid rgba(255,80,80,.2)",borderRadius:8,fontSize:12,color:"#ff8888"}}>🔐 Restricted area · AESMSL Co-presidents only</div>
      <div style={{display:"flex",gap:4,marginBottom:20,background:"rgba(0,0,0,.3)",borderRadius:10,padding:4,flexWrap:"wrap"}}>
        {[{id:"stats",l:"📊 Dashboard"},{id:"groups",l:"⚽ Results"},{id:"bracket",l:"🏆 KO"},{id:"bonus",l:"🎯 Bonus"}].map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{flex:1,minWidth:80,padding:"9px 0",border:"none",borderRadius:7,background:tab===t.id?"rgba(255,80,80,.25)":"transparent",color:tab===t.id?"#ff8888":"var(--muted)",fontWeight:600,transition:"all .2s"}}>{t.l}</button>
        ))}
      </div>
      {tab==="stats"&&(
        <div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12,marginBottom:20}}>
            {[{l:"Registered",v:users.length,i:"👥",c:"var(--azure)"},{l:"Submitted",v:users.filter(u=>!!pronos[u.id]).length,i:"📝",c:"var(--green)"},{l:"Top score",v:scoreboard[0]?.pts||0,i:"⭐",c:"var(--purple)"}].map(({l,v,i,c})=>(
              <div key={l} style={{background:"rgba(23,45,105,.6)",border:`1px solid ${c}33`,borderRadius:12,padding:16,textAlign:"center"}}>
                <div style={{fontSize:22,marginBottom:4}}>{i}</div><div style={{fontFamily:"Anton,sans-serif",fontSize:26,color:c}}>{v}</div>
                <div style={{fontSize:10,color:"var(--muted)",letterSpacing:1}}>{l.toUpperCase()}</div>
              </div>
            ))}
          </div>
          <div style={{background:"rgba(23,45,105,.5)",border:"1px solid rgba(65,161,231,.15)",borderRadius:12,overflow:"hidden"}}>
            <div style={{padding:"12px 16px",borderBottom:"1px solid rgba(65,161,231,.15)",fontFamily:"Anton,sans-serif",fontSize:14,letterSpacing:2,color:"var(--azure)"}}>LIVE LEADERBOARD</div>
            {scoreboard.length===0&&<div style={{padding:30,textAlign:"center",color:"var(--muted)"}}>No participants yet</div>}
            {scoreboard.map((u,i)=>(
              <div key={u.id} style={{display:"flex",alignItems:"center",gap:12,padding:"12px 16px",borderBottom:i<scoreboard.length-1?"1px solid rgba(255,255,255,.04)":"none"}}>
                <span style={{fontFamily:"Anton,sans-serif",fontSize:18,color:i===0?"#ffd700":i===1?"#c0c0c0":i===2?"#cd7f32":"rgba(255,255,255,.2)",minWidth:28}}>{i===0?"🥇":i===1?"🥈":i===2?"🥉":i+1}</span>
                <div style={{flex:1}}><div style={{fontWeight:600}}>{u.prenom} {u.nom}</div><div style={{fontSize:11,color:u.submitted?"var(--green)":"#ff8c42"}}>{u.submitted?"✓ Submitted":"⏳ Pending"}</div></div>
                <div style={{fontFamily:"Anton,sans-serif",fontSize:22,color:"var(--azure)"}}>{u.pts} pts</div>
              </div>
            ))}
          </div>
        </div>
      )}
      {tab==="groups"&&(
        <div>
          <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:16}}>
            {Object.keys(GROUPS).map(g=>(<button key={g} onClick={()=>setGrp(g)}
              style={{padding:"6px 12px",border:grp===g?"1px solid #ff8888":"1px solid rgba(255,80,80,.2)",borderRadius:7,background:grp===g?"rgba(255,80,80,.15)":"rgba(23,45,105,.4)",color:grp===g?"#ff8888":"var(--muted)",fontWeight:600}}>GR.{g}</button>))}
          </div>
          {GROUP_MATCHES.filter(m=>m.group===grp).map(m=>{
            const s=res.groupScores?.[m.id]||{};
            return(<div key={m.id} style={{background:"rgba(23,45,105,.4)",border:"1px solid rgba(65,161,231,.15)",borderRadius:10,padding:"10px 14px",display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
              <span style={{flex:1,fontSize:12,textAlign:"right",color:"#ccc"}}>{m.home}</span>
              <ScoreInp value={s.h} onChange={v=>updR(r=>{r.groupScores[m.id]=r.groupScores[m.id]||{};r.groupScores[m.id].h=v;})} disabled={false}/>
              <span style={{color:"var(--muted)",fontSize:11}}>–</span>
              <ScoreInp value={s.a} onChange={v=>updR(r=>{r.groupScores[m.id]=r.groupScores[m.id]||{};r.groupScores[m.id].a=v;})} disabled={false}/>
              <span style={{flex:1,fontSize:12,color:"#ccc"}}>{m.away}</span>
            </div>);
          })}
        </div>
      )}
      {tab==="bracket"&&(
        <div>
          {[{label:"R32",prefix:"r32",count:16},{label:"R16",prefix:"r16",count:8},{label:"QF",prefix:"qf",count:4},{label:"SF",prefix:"sf",count:2},{label:"🏆 FINAL",prefix:"final",count:1}].map(({label,prefix,count})=>(
            <div key={prefix} style={{marginBottom:20}}>
              <div style={{fontSize:11,fontWeight:700,letterSpacing:2,color:"#ff8888",marginBottom:8}}>WINNERS — {label}</div>
              <div style={{display:"grid",gridTemplateColumns:`repeat(${Math.min(4,count)},1fr)`,gap:8}}>
                {Array.from({length:count},(_,i)=>{const id=`${prefix}-${i+1}`;return(
                  <div key={id}><div style={{fontSize:10,color:"var(--muted)",marginBottom:3}}>{id}</div>
                    <input value={res.knockout?.[prefix]?.[id]||""} onChange={e=>updR(r=>{r.knockout[prefix]=r.knockout[prefix]||{};r.knockout[prefix][id]=e.target.value;})}
                      style={{width:"100%",padding:"8px 10px",background:"rgba(23,45,105,.6)",border:"1px solid rgba(65,161,231,.25)",borderRadius:7,color:"var(--text)",fontSize:12}} placeholder="Winning team"/>
                  </div>);
                })}
              </div>
            </div>
          ))}
        </div>
      )}
      {tab==="bonus"&&(
        <div style={{display:"flex",flexDirection:"column",gap:16}}>
          {[["champion","🏆 World Champion"],["topScorer","⚡ Top Scorer"],["darkHorse","🐴 Dark Horse"]].map(([k,label])=>(
            <div key={k}>
              <label style={{display:"block",fontSize:11,color:"var(--azure)",fontWeight:700,letterSpacing:1,marginBottom:6,textTransform:"uppercase"}}>{label}</label>
              <input value={res[k]||""} onChange={e=>updR(r=>{r[k]=e.target.value;})}
                style={{width:"100%",padding:"11px 14px",background:"rgba(23,45,105,.6)",border:"1px solid rgba(65,161,231,.25)",borderRadius:8,color:"var(--text)",fontSize:14}} placeholder={`Enter ${label.toLowerCase()}...`}/>
            </div>
          ))}
        </div>
      )}
      <div style={{marginTop:24}}>
        <button onClick={saveRes}
          style={{padding:"13px 32px",background:saved?"#1a5c1a":"rgba(255,80,80,.2)",border:saved?"none":"1px solid rgba(255,80,80,.4)",borderRadius:10,color:saved?"#fff":"#ff8888",fontFamily:"Anton,sans-serif",fontSize:16,letterSpacing:2}}>
          {saved?"✓ RESULTS SAVED":"💾 SAVE RESULTS"}
        </button>
      </div>
    </div>
  );
}

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
export default function App(){
  const [user,setUser]=useState(null);
  const [view,setView]=useState("leaderboard");
  const [results,setResults]=useState(null);
  const [loading,setLoading]=useState(true);

  useEffect(()=>{fbGetResults().then(r=>{if(r)setResults(r);setLoading(false);});},[]);

  if(loading) return(<div style={{minHeight:"100vh",background:"var(--bg)",display:"flex",alignItems:"center",justifyContent:"center"}}><G/><div style={{fontFamily:"Anton,sans-serif",fontSize:28,color:"var(--azure)",letterSpacing:4}}>⚽ LOADING...</div></div>);
  if(!user) return <AuthView onLogin={u=>{setUser(u);setView(u.isAdmin?"admin":"leaderboard");}}/>;

  const navItems=[{id:"leaderboard",icon:"🏅",label:"Leaderboard"},{id:"predictions",icon:"📝",label:"Predictions"},...(user.isAdmin?[{id:"admin",icon:"⚙️",label:"Admin"}]:[])];

  return(
    <>
      <G/>
      <div style={{minHeight:"100vh",background:"var(--bg)"}}>
        <header style={{background:"linear-gradient(90deg,#0d1d4a,var(--night),#0d1d4a)",borderBottom:"2px solid var(--blue)",padding:"0 20px",display:"flex",alignItems:"stretch",justifyContent:"space-between",position:"sticky",top:0,zIndex:100,boxShadow:"0 4px 30px rgba(4,103,172,.3)"}}>
          <div style={{display:"flex",alignItems:"center",gap:14,padding:"8px 0"}}>
            <img src={LOGO_S} alt="AESMSL" style={{height:40}}/>
            <div style={{width:1,height:28,background:"rgba(65,161,231,.3)"}}/>
            <div><div style={{fontFamily:"Anton,sans-serif",fontSize:14,letterSpacing:3,color:"var(--azure)",lineHeight:1.1}}>WORLD CUP 2026</div><div style={{fontSize:9,letterSpacing:2,color:"var(--muted)"}}>PREDICTIONS — AESMSL</div></div>
          </div>
          <nav style={{display:"flex",alignItems:"stretch"}}>
            {navItems.map(n=>(<button key={n.id} onClick={()=>setView(n.id)}
              style={{padding:"0 18px",border:"none",background:"transparent",fontWeight:600,color:view===n.id?"var(--azure)":"var(--muted)",borderBottom:view===n.id?"3px solid var(--azure)":"3px solid transparent",transition:"all .15s"}}>
              {n.icon} {n.label}
            </button>))}
          </nav>
          <div style={{display:"flex",alignItems:"center",gap:10,padding:"8px 0"}}>
            <div style={{textAlign:"right"}}><div style={{fontWeight:600}}>{user.prenom} {user.nom}</div>{user.isAdmin&&<div style={{fontSize:10,color:"#ff8888",letterSpacing:1}}>ADMIN</div>}</div>
            <button onClick={()=>setUser(null)} style={{padding:"6px 12px",background:"rgba(255,255,255,.05)",border:"1px solid rgba(255,255,255,.1)",borderRadius:6,color:"var(--muted)",fontSize:11}}>LOG OUT</button>
          </div>
        </header>
        <div style={{background:"rgba(4,103,172,.15)",borderBottom:"1px solid rgba(65,161,231,.15)",padding:"5px 0",overflow:"hidden"}}>
          <div style={{fontSize:11,color:"var(--azure)",letterSpacing:1,display:"inline-block",animation:"ticker 25s linear infinite",whiteSpace:"nowrap"}}>
            &nbsp;&nbsp;⚽ FIFA WORLD CUP 2026 · 48 TEAMS · JUNE 11 — JULY 19 · USA · CANADA · MEXICO &nbsp;&nbsp; 🏆 AESMSL PREDICTIONS · GOOD LUCK TO ALL! &nbsp;&nbsp; 🔥 Sports Management School Lausanne &nbsp;&nbsp;
          </div>
        </div>
        <main style={{maxWidth:1100,margin:"0 auto",padding:"24px 20px"}}>
          {view==="leaderboard"&&<Leaderboard uid={user.id} results={results}/>}
          {view==="predictions"&&<PredictionsView user={user}/>}
          {view==="admin"&&user.isAdmin&&<AdminView onResultsChange={setResults}/>}
        </main>
        <footer style={{borderTop:"1px solid rgba(65,161,231,.1)",padding:"16px 20px",display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:8}}>
          <img src={LOGO_P} alt="AESMSL" style={{height:28,opacity:.4}}/>
          <span style={{fontSize:11,color:"rgba(255,255,255,.15)"}}>AESMSL · Student Association · Sports Management School Lausanne · World Cup 2026</span>
        </footer>
      </div>
    </>
  );
}
